// CAP CDS — Domain Model (db/schema.cds)
namespace my.bookshop;

entity Books {
  key ID   : Integer;
  title    : String(100);
  author   : Association to Authors;
  stock    : Integer;
  price    : Decimal(10,2);
}

entity Authors {
  key ID   : Integer;
  name     : String(100);
  books    : Association to many Books on books.author = $self;
}

// CAP CDS — Service Definition (srv/cat-service.cds)
using my.bookshop from '../db/schema';

service CatalogService {
  entity Books as projection on my.bookshop.Books;
  entity Authors as projection on my.bookshop.Authors;

  @readonly
  entity TopSellers as select from Books
    where stock > 0
    order by stock desc;
}

/*
  CAP generates:
  - HANA/PostgreSQL tables: my_bookshop_Books
  - OData V4 EDMX with CatalogService
  - Generic CRUD handlers for Books, Authors, TopSellers
  - CORS, CSRF, authorization middleware
*/

// CAP — Node.js handler (srv/cat-service.js)
const cds = require('@sap/cds');

module.exports = cds.service.impl(async function() {
  const { Books } = this.entities;

  // Before READ handler — validation / authorization
  this.before('READ', Books, async (req) => {
    if (!req.user.is('admin')) {
      req.query.where('stock > 0'); // Non-admin sees only in-stock
    }
  });

  // On READ handler — custom logic after generic handler
  this.on('READ', Books, async (req, next) => {
    const result = await next(); // Delegates to generic handler
    return result.map(book => ({
      ...book,
      title: book.title.toUpperCase()
    }));
  });

  // Custom action — not CRUD
  this.on('restock', Books, async (req) => {
    const { ID, quantity } = req.data;
    await UPDATE(Books).set({ stock: { '+=': quantity } }).where({ ID });
    return `Restocked book ${ID} by ${quantity}`;
  });
});

