ENDCLASS.

CLASS zcl_rap_book_handler IMPLEMENTATION.
  METHOD before_read.
    IF NOT cl_abap_context=>get_auth()->is_admin( ).
      INSERT VALUE #( property = 'STOCK' sign = 'I'
