// CAP CDS — Domain Model (db/schema.cds)
namespace sap.sales;

using { Currency, Country, Address } from '@sap/cds/common';

entity Customers {
  key ID        : UUID;
      name      : String(100);
      email     : String(200);
      phone     : String(30);
      address   : Composition of Address;
      createdAt : Timestamp;
      createdBy : String(100);
}

entity Orders {
  key ID        : UUID;
      orderNo   : String(20) not null;
      customer  : Association to Customers;
      total     : Decimal(16,2);
      currency  : Currency;
      status    : String(10) enum {
        draft; confirmed; shipped; invoiced; cancelled
      };
      items     : Composition of many OrderItems
                    on items.parent = $self;
      createdAt : Timestamp;
}

entity OrderItems {
  key ID        : UUID;
      parent    : Association to Orders;
      product   : Association to Products;
      quantity  : Integer;
      unitPrice : Decimal(16,4);
      lineTotal : Decimal(16,2);
}

entity Products {
  key ID        : UUID;
      name      : String(100);
      price     : Decimal(16,2);
      currency  : Currency;
      stock     : Integer;
      category  : String(50);
}

/*
  Staff+ Notes:
  - Compositions vs Associations: Composition = owned lifecycle (delete Order cascades to OrderItems).
  - Association = reference without lifecycle coupling (Orders.customer → Customers).
  - @sap/cds/common provides reusable types (Currency, Country, Address).
  - UUID keys are preferred for cloud-native apps (no sequential gaps, safe for multi-tenant).
*/

