// CAP — Node.js Handlers (srv/admin-service.js)
const cds = require('@sap/cds');

module.exports = cds.service.impl(async function() {
  const { Orders, OrderItems, Products } = this.entities;

  // BEFORE hook — validate and enforce invariants
  this.before('CREATE', Orders, async (req) => {
    const { customer_ID, items } = req.data;
    if (!customer_ID) {
      req.error(400, 'Customer ID is required');
    }
    if (!items || items.length === 0) {
      req.error(400, 'At least one item is required');
    }
    // Check customer exists
    const customer = await SELECT.one.from(CDS.Customers)
      .where({ ID: customer_ID });
    if (!customer) {
      req.error(404, `Customer ${customer_ID} not found`);
    }
  });

  // ON hook — override UPDATE with custom stock validation
  this.on('UPDATE', OrderItems, async (req, next) => {
    const { product_ID, quantity } = req.data;
    const product = await SELECT.one.from(Products)
      .where({ ID: product_ID });
    if (product && product.stock < quantity) {
      req.error(400, `Insufficient stock: ${product.stock} available`);
    }
    return next(); // Delegates to generic UPDATE
  });

  // AFTER hook — enrich response with computed data
  this.after('READ', Orders, async (order, req) => {
    if (order.total > 10000) {
      order.requiresApproval = true;
    }
    return order;
  });

  // Custom action — not tied to CRUD
  this.on('approve', Orders, async (req) => {
    const { ID } = req.data;
    const order = await SELECT.one.from(Orders).where({ ID });
    if (!order) return req.error(404, 'Order not found');
    if (order.status !== 'pending_approval') {
      return req.error(400, 'Order is not pending approval');
    }
    await UPDATE(Orders).set({ status: 'approved' }).where({ ID });
    // Emit event for downstream consumers
    await cds.emit('OrderApproved', { orderID: ID });
    return { status: 'approved', orderID: ID };
  });
});

