// CAP — Tenant-Aware Service (srv/tenant-aware.js)
const cds = require('@sap/cds');

module.exports = cds.service.impl(async function() {
  const { Orders } = this.entities;

  // Tenant context is automatically available via cds.context.tenant
  // The @cds.tenant annotation in CDS isolates data per tenant

  this.before('CREATE', Orders, async (req) => {
    // Automatically set the tenant from JWT context
    const tenant = cds.context.tenant;
    req.data.tenantID = tenant;

    // Validate tenant-specific configuration
    const config = await cds.tx(async () => {
      return SELECT.one.from('sap.common.TenantConfigurations')
        .where({ tenantID: tenant });
    });
    if (config?.orderLimit && req.data.total > config.orderLimit) {
      req.error(400, `Order exceeds tenant limit of ${config.orderLimit}`);
    }
  });

  // Side-by-side extension: read custom fields added by customer
  this.after('READ', Orders, async (order, req) => {
    // Check if this tenant has extended the Orders entity
    const extensions = await cds.db.getExtensionFields('Orders', req.tenant);
    if (extensions && order.__extensionFields) {
      Object.assign(order, order.__extensionFields);
    }
    return order;
  });
});

// Customer-side extension (added by customer, not SaaS provider)
// extend schema.cds
using { sap.sales.Orders } from './db/schema';

// Customer adds custom fields to Orders
extend sap.sales.Orders with {
  CustomerPriority : String(10);
  ApprovalChain    : String(100);
};

// Customer adds custom validation
extend sap.sales.Orders with {
  validate priority : CustomerPriority in ('Low', 'Medium', 'High', 'Urgent');
};

