// srv/cat-service.cds
using { sap.sales } from '../db/schema';

service AdminService @(requires: 'SalesAdmin') {
  entity Orders as projection on sap.sales.Orders;
  entity Customers as projection on sap.sales.Customers;

  action promote(ID: UUID) returns String;
}

service UserService {
  @restrict: [
    { grant: 'READ', to: 'SalesRead' },
    { grant: 'WRITE', to: 'SalesWrite' },
    {
      grant: ['READ', 'WRITE'],
      to: 'SalesAdmin',
      where: 'tenantID = $user.tenant'
    }
  ]
  entity Orders as projection on sap.sales.Orders;

  @readonly
  entity MyOrders as select from sap.sales.Orders
    where tenantID = $user.tenant;
}

