// CAP — Performance Optimization Examples

// 1. Use .where() clauses to push filters to DB (BAD vs GOOD)
// BAD — loads all rows into memory
const allOrders = await SELECT.from(Orders);
const filtered = allOrders.filter(o => o.total > 1000);

// GOOD — pushes WHERE to database
const filtered = await SELECT.from(Orders)
  .where({ total: { '>': 1000 } })
  .limit(100);

// 2. Use projections to limit columns fetched
// BAD — SELECT *
const orders = await SELECT.from(Orders);

// GOOD — SELECT specific columns
const orders = await SELECT.from(Orders)
  .columns(['ID', 'orderNo', 'total', 'status']);

// 3. Batch reads — avoid N+1 in loops
// BAD — N+1: query per order item
for (const order of orders) {
  order.items = await SELECT.from(OrderItems)
    .where({ parent_ID: order.ID });
}

// GOOD — single batch query
const itemMap = new Map();
const allItems = await SELECT.from(OrderItems)
  .where({ parent_ID: { IN: orders.map(o => o.ID) } });
for (const item of allItems) {
  (itemMap.get(item.parent_ID) || []).push(item);
}

// 4. Enable caching for read-only entities
// package.json or .cdsrc.json
{
  "cds": {
    "caching": {
      "enabled": true,
      "provider": "redis",
      "ttl": {
        "sap.sales.Products": 3600,
        "sap.sales.Customers": 300
      },
      "redis": {
        "host": "myredis.cache.carbon.com",
        "port": 6379
      }
    },
    "query": {
      "max": {
        "limit": 1000,
        "depth": 3
      }
    }
  }
}

